/// Model for Kemetic day information
class KemeticDayInfo {
  final String kemeticDate;
  final String season;
  final String month;
  final String decanName;
  final String starCluster;
  final String maatPrinciple;
  final String cosmicContext;
  final List<DecanDayInfo> decanFlow;
  final MeduNeterKey meduNeter;

  KemeticDayInfo({
    required this.kemeticDate,
    required this.season,
    required this.month,
    required this.decanName,
    required this.starCluster,
    required this.maatPrinciple,
    required this.cosmicContext,
    required this.decanFlow,
    required this.meduNeter,
  });
}

class DecanDayInfo {
  final int day;
  final String theme;
  final String action;
  final String reflection;

  DecanDayInfo({
    required this.day,
    required this.theme,
    required this.action,
    required this.reflection,
  });
}

class MeduNeterKey {
  final String glyph;
  final String colorFrequency;
  final String mantra;

  MeduNeterKey({
    required this.glyph,
    required this.colorFrequency,
    required this.mantra,
  });
}

/// Sample data for Day 11 (Renwet II, Day 1)
class KemeticDayData {
  static ({int kMonth, int kDay, int decan})? _parseDayKeyForDecan(
    String dayKey,
  ) {
    final parts = dayKey.split('_');
    if (parts.length < 3) return null;
    final month = getMonthByKey(parts[0])?.id;
    final kDay = int.tryParse(parts[1]);
    final decan = int.tryParse(parts[2]);
    if (month == null || kDay == null || decan == null) return null;
    return (kMonth: month, kDay: kDay, decan: decan);
  }

  static String? resolveDecanNameFromKey(
    String dayKey, {
    bool expanded = false,
  }) {
    final parsed = _parseDayKeyForDecan(dayKey);
    if (parsed == null) return null;
    return DecanMetadata.decanNameFor(
      kMonth: parsed.kMonth,
      kDay: parsed.kDay,
      expanded: expanded,
    );
  }

