    const month =
        "Rekh-Wer (Rḫ-wr) — “Great Knowing,” where understanding must prove itself through structure, measure, and responsibility";
    return _buildGeneratedDecanEntries(
      keyPrefix: "rekhwer",
      decan: 1,
      decanLabel: "Rekh-Wer I",
      monthLabelForDate: "Rekh-Wer",
