  static KemeticDayInfo? getInfoForDay(String dayKey) {
    return dayInfoMap[dayKey];
  }

  /// Month key override map.
  /// IMPORTANT: Keep in sync with the override map in day_key.dart.
  static const Map<int, String> _monthKeyOverride = {
    2: 'paophi',
    5: 'sefbedet',
    10: 'henti',
    11: 'ipt',
    12: 'mswtRa',
  };

  /// Parses a dayKey to extract (month, day, year?).
  /// Handles:
  /// - "epagomenal_1_1"
  /// - "epagomenal_1_2026"
  /// - `<monthKey>_<day>_<decan>`
  static ({int month, int day, int? year})? _parseDayKey(String dayKey) {
    // Epagomenal days
    if (dayKey.startsWith('epagomenal_')) {
      final parts = dayKey.split('_'); // epagomenal, <day>, [year]
      if (parts.length >= 2) {
        final day = int.tryParse(parts[1]);
        if (day != null && day >= 1 && day <= 6) {
          final int? yearFromKey = parts.length >= 3
              ? int.tryParse(parts[2])
              : null;
          return (month: 13, day: day, year: yearFromKey);
        }
      }
      return null;
    }

    // Regular format: "<monthKey>_<day>_<decan>"
    final parts = dayKey.split('_');
    if (parts.length < 2) return null;

    final monthKey = parts[0];
    final dayStr = parts[1];
    final day = int.tryParse(dayStr);
    if (day == null || day < 1 || day > 30) return null;

    // Reverse lookup month ID from monthKey
    // First check override map
    final overrideEntry = _monthKeyOverride.entries.firstWhere(
      (e) => e.value == monthKey,
      orElse: () => const MapEntry(0, ''),
    );
    if (overrideEntry.key != 0) {
      return (month: overrideEntry.key, day: day, year: null);
    }

    // Then fall back to "real" month metadata
    for (int monthId = 1; monthId <= 12; monthId++) {
      final month = getMonthById(monthId);
      if (month.key == monthKey) {
        return (month: monthId, day: day, year: null);
      }
    }

    return null;
  }

  /// Calculates the Gregorian date label for a given dayKey.
  ///
  /// - Uses year embedded in the key if present (epagomenal_1_2026),
  ///   otherwise falls back to [kYearParam], otherwise 1.
  /// - Handles leap years via KemeticMath.toGregorian().
  /// - Treats the result as a pure calendar date (no local timezone shifting).
  static String calculateGregorianDate(String dayKey, {int? kYearParam}) {
    final parsed = _parseDayKey(dayKey);
    if (parsed == null) {
      return 'Unknown Date';
    }

    final int kMonth = parsed.month;
    final int kDay = parsed.day;

    // Choose a year: from key → from param → default 1
    final int kYear = (parsed.year ?? kYearParam ?? 1);
    if (kYear < 1) {
      return 'Invalid Year';
    }

    // Validate day ranges
    if (kMonth == 13) {
      // Epagomenal month
      final maxEpi = KemeticMath.isLeapKemeticYear(kYear) ? 6 : 5;
      if (kDay < 1 || kDay > maxEpi) {
        return 'Invalid Epagomenal Day';
      }
    } else {
      // Regular months
      if (kDay < 1 || kDay > 30) {
        return 'Invalid Day';
      }
    }

    try {
      // This returns a UTC DateTime corresponding to the Kemetic date.
      final DateTime gregorianUtc = KemeticMath.toGregorian(
        kYear,
        kMonth,
        kDay,
      );

      // 🔑 KEY FIX:
      // For day cards, we only care about the calendar date,
      // not the local-time shift. Strip the time/zone.
      final DateTime dateOnly = DateTime(
        gregorianUtc.year,
        gregorianUtc.month,
        gregorianUtc.day,
      );

      return _formatGregorianDateString(dateOnly);
    } catch (_) {
      return 'Date Calculation Error';
    }
  }

  /// Formats a DateTime as "Month Day, Year" (e.g., "March 20, 2025").
  static String _formatGregorianDateString(DateTime date) {
    const monthNames = <String>[
      'January',
      'February',
      'March',
      'April',
      'May',
      'June',
      'July',
      'August',
      'September',
      'October',
      'November',
      'December',
    ];

    return '${monthNames[date.month - 1]} ${date.day}, ${date.year}';
  }
}

/// Dropdown card widget for displaying Kemetic day information
class KemeticDayDropdown extends StatelessWidget {
  final KemeticDayInfo dayInfo;
  final VoidCallback onClose;
  final String dayKey;
  final int kYear;
  static const List<String> _meduFontFallback = ['GentiumPlus'];

  const KemeticDayDropdown({
    super.key,
    required this.dayInfo,
    required this.onClose,
    required this.dayKey,
    required this.kYear,
  });

  @override
  Widget build(BuildContext context) {
    final parsedKey = KemeticDayData._parseDayKey(dayKey);
    final bool isEpagomenal =
        parsedKey?.month == 13 || dayKey.startsWith('epagomenal_');
    final int? epagomenalDay = isEpagomenal ? parsedKey?.day : null;

    final String monthLine = isEpagomenal
        ? (dayInfo.month.isNotEmpty
              ? dayInfo.month
              : 'Heriu Renpet — The Births of the Gods — five days beyond the year')
        : dayInfo.month;
    final screenWidth = MediaQuery.of(context).size.width;
    final cardWidth = screenWidth > 600 ? 500.0 : screenWidth * 0.85;
    final resolvedDecanName =
        KemeticDayData.resolveDecanNameFromKey(dayKey, expanded: true) ??
        dayInfo.decanName;

    final String decanLine = isEpagomenal
        ? (dayInfo.decanName.isNotEmpty
              ? dayInfo.decanName
              : _epagomenalDayTitle(epagomenalDay))
        : resolvedDecanName;

    // Calculate the date string
    final String gregorianDateString = KemeticDayData.calculateGregorianDate(
      dayKey,
      kYearParam: kYear,
    );

    // Build speech lines (prefer curated speechName overrides when available)
    final parsedDecan = KemeticDayData._parseDayKeyForDecan(dayKey);
    final monthId = parsedDecan?.kMonth;
    final KemeticMonth? monthMeta =
        (monthId != null && monthId >= 1 && monthId <= 13)
        ? getMonthById(monthId)
        : null;

    final String monthSpeakLine = monthMeta != null
        ? SpeechResolver.month(
            month: monthMeta,
            displayName: _stripEnglishCue(monthLine),
          )
        : _stripEnglishCue(dayInfo.month);

    String decanSpeakLine;
    if (!isEpagomenal &&
        parsedDecan != null &&
        parsedDecan.kMonth >= 1 &&
        parsedDecan.kMonth <= 12 &&
        parsedDecan.decan >= 1 &&
        parsedDecan.decan <= 3) {
      final decanId = decanIdFromMonthAndIndex(
        monthIndex: parsedDecan.kMonth,
        decanInMonth: parsedDecan.decan,
      );
      final decanNames = DecanMetadata.decanNames[parsedDecan.kMonth];
      final decanLabel =
          (decanNames != null && decanNames.length >= parsedDecan.decan)
          ? decanNames[parsedDecan.decan - 1]
          : 'Decan ${parsedDecan.decan}';
      decanSpeakLine = SpeechResolver.decan(
        decanId: decanId,
        displayName: decanLabel,
      );
    } else {
      decanSpeakLine = SpeechResolver.decan(
        decanId: 0,
        displayName: _stripEnglishCue(decanLine),
      );
    }

    // Debug: trace TTS wiring for day card
    debugPrint('--- DAY CARD TTS DEBUG ---');
    debugPrint('dayKey=$dayKey');
    debugPrint('parsedDecan=$parsedDecan');
    debugPrint('isEpagomenal=$isEpagomenal');
    debugPrint('monthLine(display)=$monthLine');
    debugPrint('monthSpeakLine(resolved)=$monthSpeakLine');
    debugPrint(
      'monthSpeechHit=${monthId != null ? monthSpeechNames.containsKey(monthId) : 'no-monthId'}',
    );
    debugPrint('decanLine(display)=$decanLine');
    debugPrint('resolvedDecanName=$resolvedDecanName');
    if (parsedDecan != null &&
        parsedDecan.kMonth >= 1 &&
        parsedDecan.kMonth <= 12) {
      final testDecanId = decanIdFromMonthAndIndex(
        monthIndex: parsedDecan.kMonth,
        decanInMonth: parsedDecan.decan,
      );
      debugPrint('decanSpeechHit=${decanSpeechNames.containsKey(testDecanId)}');
      debugPrint(
        'decanSpeechLabelHit=${decanSpeechNamesByLabel.containsKey(_stripEnglishCue(resolvedDecanName))}',
      );
      debugPrint('decanSpeakLine(resolved)=$decanSpeakLine');
    } else {
      debugPrint('decanSpeakLine(resolved)=$decanSpeakLine');
    }

    return Material(
      color: Colors.transparent,
      child: Container(
        width: cardWidth,
        constraints: BoxConstraints(
          maxHeight: MediaQuery.of(context).size.height * 0.75,
        ),
        decoration: BoxDecoration(
          color: const Color(0xFF000000), // True black background
          borderRadius: BorderRadius.circular(16),
          border: Border.all(
            color: const Color(0xFFC9A961), // Richer gold border
            width: 1,
          ),
          boxShadow: [
            BoxShadow(
              color: Colors.black.withValues(alpha: 0.5),
              blurRadius: 30,
              offset: const Offset(0, 10),
            ),
          ],
        ),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            // Header with close button
            Container(
              padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 14),
              decoration: BoxDecoration(
                color: const Color(0xFF000000), // True black header
                borderRadius: const BorderRadius.only(
                  topLeft: Radius.circular(16),
                  topRight: Radius.circular(16),
                ),
                border: const Border(
                  bottom: BorderSide(
                    color: Color(0xFFC9A961), // Richer gold divider
                    width: 1,
                  ),
                ),
              ),
              child: Row(
                children: [
                  Expanded(
                    child: Text(
                      '☀️ Kemetic Date Alignment',
                      style: const TextStyle(
                        fontSize: 18,
                        fontWeight: FontWeight.bold,
                        color: Color(0xFFC9A961), // Richer gold color
                      ),
                    ),
                  ),
                  IconButton(
                    icon: const Icon(Icons.close, color: Color(0xFFC9A961)),
                    onPressed: () {
                      SpeechService.instance.stop();
                      onClose();
                    },
                    padding: EdgeInsets.zero,
                    constraints: const BoxConstraints(),
                  ),
                ],
              ),
            ),
            // Scrollable content
            Flexible(
              child: Scrollbar(
                thumbVisibility: true,
                child: SingleChildScrollView(
                  padding: const EdgeInsets.all(20),
                  child: DefaultTextStyle.merge(
                    style: const TextStyle(
                      fontFamilyFallback: _meduFontFallback,
                    ),
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        _buildInfoSection(
                          'Gregorian Date:',
                          gregorianDateString,
                        ),
                        _buildInfoSection('Kemetic Date:', dayInfo.kemeticDate),
                        _buildInfoSection('Season:', dayInfo.season),
                        _buildInfoSectionWithSpeech(
                          label: 'Month:',
                          value: monthLine,
                          englishCue: null,
                          speakOverride: monthSpeakLine,
                          isPhonetic: true,
                        ),
                        _buildInfoSectionWithSpeech(
                          label: isEpagomenal
                              ? 'Epagomenal Day:'
                              : 'Decan Name:',
                          value: decanLine,
                          englishCue: null,
                          speakOverride: decanSpeakLine,
                          isPhonetic: true,
                        ),
                        if (!isEpagomenal)
                          _buildInfoSection(
                            'Star Cluster:',
                            dayInfo.starCluster,
                          ),
                        _buildInfoSection(
                          'Ma\'at Principle:',
                          dayInfo.maatPrinciple,
                        ),
                        const SizedBox(height: 20),
                        _buildSectionHeader('△ Cosmic Context'),
                        const SizedBox(height: 8),
                        Text(
                          dayInfo.cosmicContext,
                          style: const TextStyle(
                            fontSize: 14,
                            color: Color(0xFFCCCCCC),
                            height: 1.5,
                            fontFamilyFallback: _meduFontFallback,
                          ),
                        ),
                        const SizedBox(height: 24),
                        _buildSectionHeader(
                          isEpagomenal ? '▽ Epagomenal Flow' : '▽ Decan Flow',
                        ),
                        const SizedBox(height: 12),
                        _buildDecanFlowTable(context),
                        const SizedBox(height: 24),
                        _buildSectionHeader('▽ Medu Neter Key'),
                        const SizedBox(height: 12),
                        _buildMeduNeterSection(context),
                        const SizedBox(height: 8), // Bottom padding
                      ],
                    ),
                  ),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }

  String _epagomenalDayTitle(int? day) {
    switch (day) {
      case 1:
        return 'Birth of Asar (Osiris)';
      case 2:
        return 'Birth of Heru-wer (Horus the Elder)';
      case 3:
        return 'Birth of Set';
      case 4:
        return 'Birth of Aset (Isis)';
      case 5:
        return 'Birth of Nebet-Het (Nephthys)';
      default:
        return 'Heriu Renpet — Sacred Day';
    }
  }

  Widget _buildInfoSection(String label, String value) {
    return Padding(
      padding: const EdgeInsets.only(bottom: 8),
      child: RichText(
        text: TextSpan(
          style: const TextStyle(
            fontSize: 14,
            color: Color(0xFFCCCCCC),
            fontFamilyFallback: _meduFontFallback,
          ),
          children: [
            TextSpan(
              text: '$label ',
              style: const TextStyle(
                fontWeight: FontWeight.bold,
                color: Color(0xFFC9A961), // Richer gold for labels
                fontFamilyFallback: _meduFontFallback,
              ),
            ),
            TextSpan(text: value),
          ],
        ),
      ),
    );
  }

  String _stripEnglishCue(String s) {
    // Remove anything in parentheses and trim.
    return s.split('(').first.trim();
  }

  Widget _buildInfoSectionWithSpeech({
    required String label,
    required String value,
    String? englishCue,
    String? speakOverride,
    bool isPhonetic = false,
  }) {
    final hasOverride =
        speakOverride != null && speakOverride.trim().isNotEmpty;
    final speakLine = hasOverride
        ? speakOverride.trim()
        : (englishCue == null || englishCue.trim().isEmpty
              ? value.trim()
              : '${value.trim()}. ${englishCue.trim()}.');

    return Padding(
